Resposta:
To import a Word document into Adobe InDesign **without losing text formatting**, you can use **Adobe's built-in scripting capabilities** via **ExtendScript (JavaScript for ScriptUI)** or **AppleScript**, depending on your environment.

Below is a **JavaScript (ExtendScript)** script that imports a Word document into InDesign while **preserving text formatting, styles, fonts, and layout** as much as possible.

> ✅ **Requirements:**
> - Adobe InDesign (CC 2017 or later)
> - Script is run from InDesign's Scripts panel or via File > Scripts > Browse

---

### ✅ **Script: Import Word DOCX with Formatting (Preserve Styles & Layout)**

```javascript
// Import Word DOCX into InDesign with formatting preservation
// Requires: Microsoft Word installed and document path valid

#target "InDesign"

if (app.documents.length === 0) {
    // Start a new document
    app.documents.add();
}

var doc = app.activeDocument;
var wordDocPath = "C:/Path/To/Your/Document.docx"; // CHANGE THIS PATH

// Check if file exists
if (!FileExists(wordDocPath)) {
    alert("Word document not found: " + wordDocPath);
    exit();
}

// Import the DOCX file
var imported = InDesign.importFile(wordDocPath, "word");

if (!imported) {
    alert("Failed to import Word document.");
    exit();
}

// Optional: Set import preferences to preserve formatting
var importOptions = InDesign.importOptions(imported);
importOptions.preserveStyles = true;
importOptions.preserveFonts = true;
importOptions.preserveHyphenation = true;
importOptions.preserveTextWrapping = true;
importOptions.preserveMargins = true;
importOptions.preserveColumns = true;
importOptions.preserveTables = true;
importOptions.pres

